#include <iostream>
#include <string>

class GameCharacter {
private:
    std::string name;
    int health;
    int maxHealth;
    int attack;
    int* buffPtr;  // Pointer to demonstrate destructor

public:
    // 1. Default constructor (no parameters)
    GameCharacter() {
        name = "Unknown";
        health = 100;
        maxHealth = 100;
        attack = 10;
        buffPtr = new int(0);  // Allocate memory
        std::cout << "Default constructor called for " << name << std::endl;
    }

    // 2. Parameterized constructor
    GameCharacter(std::string n, int h, int a) {
        name = n;
        health = h;
        maxHealth = h;
        attack = a;
        buffPtr = new int(0);  // Allocate memory
        std::cout << "Parameterized constructor called for " << name << std::endl;
    }

    // 3. Copy constructor
    GameCharacter(const GameCharacter& other) {
        name = other.name + " (clone)";
        health = other.health;
        maxHealth = other.maxHealth;
        attack = other.attack;
        buffPtr = new int(*other.buffPtr);  // Deep copy
        std::cout << "Copy constructor called for " << name << std::endl;
    }

    // 4. Destructor
    ~GameCharacter() {
        delete buffPtr;  // Free allocated memory!
        std::cout << "Destructor called for " << name << std::endl;
    }

    void display() {
        std::cout << "Name: " << name << ", Health: " << health 
                  << "/" << maxHealth << ", Attack: " << attack << std::endl;
    }

    void setBuff(int value) {
        *buffPtr = value;
        attack += value;
        std::cout << name << " buffed by " << value << "! New attack: " << attack << std::endl;
    }
};

int main() {
    std::cout << "=== Constructors & Destructors ===" << std::endl;

    // 1. Default constructor
    GameCharacter unknown;
    unknown.display();

    // 2. Parameterized constructor
    GameCharacter hero("Aragorn", 120, 25);
    hero.display();
    hero.setBuff(5);

    // 3. Copy constructor
    GameCharacter clone = hero;  // Copy
    clone.display();

    std::cout << "\n--- End of main ---" << std::endl;
    // Destructors called automatically when objects go out of scope

    return 0;
}

phase1.explanation:
🎮 **Constructors create objects. Destructors clean them up.**

**Constructor types:**

| Type | When Called | Purpose |
|------|-------------|---------|
| Default | No arguments | Initialize with defaults |
| Parameterized | With arguments | Custom initialization |
| Copy | Copy existing object | Duplicate an object |

**Constructor syntax:**
```cpp
class Player {
public:
    // Default
    Player() { health = 100; }

    // Parameterized
    Player(int h) { health = h; }

    // Copy
    Player(const Player& other) { health = other.health; }
};
```

**Destructor:**
```cpp
~Player() {
    // Cleanup code
    // Called when object is destroyed
}
```

**Why destructors matter:**
- Free memory (pointers)
- Close files
- Release resources

**PlusPlus-chan says:**
"Java-chan has garbage collection. I have destructors. You control when resources are freed. That's power."

**The Rule of Three:**
If you need a destructor, you probably also need:
1. Copy constructor
2. Copy assignment operator

We'll cover this in detail later.

