#include <iostream>
#include <string>

class Potion {
private:
    std::string name;
    int healAmount;
    int quantity;

public:
    // Default constructor
    Potion() {
        name = "Unknown Potion";
        healAmount = 10;
        quantity = 1;
        std::cout << "Default potion created!" << std::endl;
    }

    // Parameterized constructor
    Potion(std::string n, int h, int q) {
        name = n;
        healAmount = h;
        quantity = q;
        std::cout << "Potion '" << name << "' created!" << std::endl;
    }

    // Copy constructor
    Potion(const Potion& other) {
        name = other.name;
        healAmount = other.healAmount;
        quantity = other.quantity;
        std::cout << "Copying potion '" << name << "'..." << std::endl;
    }

    // Destructor
    ~Potion() {
        std::cout << "Potion destroyed: " << name << std::endl;
    }

    void use() {
        if (quantity > 0) {
            quantity--;
            std::cout << "Used " << name << "! Healed " << healAmount << " HP!" << std::endl;
        } else {
            std::cout << "No " << name << " left!" << std::endl;
        }
    }
};

int main() {
    Potion defaultPotion;

    Potion healthPotion("Health Potion", 50, 3);
    healthPotion.use();

    Potion copyPotion = healthPotion;
    copyPotion.use();

    return 0;
}
